            //////////////////////////////////////////////////////////////////////////////////////

            //Variance model
            //List<double> residuals = new List<double>();
            //for (int i = 0; i < dh._inputs.Count; ++i)
            //{
            //    double y = km_expectaion.ComputeOutput(dh._inputs[i]);
            //    residuals.Add((y - dh._target[i]) * (y - dh._target[i]));
            //}

            //KolmogorovModel km_variance = new KolmogorovModel(dh._inputs, residuals, new int[] { 3, 3, 3 });
            //int NL = 7;
            //int[] blocks = new int[NL];
            //for (int m = 0; m < NL; ++m)
            //{
            //    blocks[m] = 3;
            //}
            //km_variance.GenerateInitialOperators(NL, blocks);
