            ///////////////////////////////////////////////////////////////////////////////////////
  
            DateTime start = DateTime.Now;
            Console.WriteLine("Resorting...");

            //Sliding window model
            Resorter resorter = new Resorter();
            resorter.ReadData(dh);
            resorter.Resort(1);
            resorter.Resort(2);
            resorter.Resort(4);
            resorter.Resort(8);
            resorter.Resort(16);
            resorter.Resort(32);
 
            SlidingKMEnsemple slider = new SlidingKMEnsemple(dh._inputs, dh._target);
            slider.BuildModels(16, 64);

            DateTime end = DateTime.Now;
            TimeSpan duration = end - start;
            double time = duration.Minutes * 60.0 + duration.Seconds + duration.Milliseconds / 1000.0;
            Console.WriteLine("Processing time for DDR {0:####.00} seconds", time);

            //Accuracy test
            int NTests = 100;
            double mean_dist = 0.0;
            double mean_CVM = 0.0;
            for (int i = 0; i < NTests; ++i)
            {
                double[] randomInput = dh.MakeRandomInput();
                //double predictedVar = km_variance.ComputeOutput(randomInput);
                //double[] knn = Static.GetKNNSample(dh._inputs, dh._target, randomInput, predictedVar);
                double[] monte_carlo = dh.GetMonteCarloSample(randomInput, 4096);
                double[] ddr = slider.GetOutput(randomInput, 0.2, 10);
                List<double> monte_carlo_list = new List<double>(monte_carlo);
                List<double> ddr_list = new List<double>(ddr);

                List<double> monte_carlo_medians = Static.MedianSplit(monte_carlo, 5);
                List<double> ddr_medians = Static.MedianSplit(ddr, 5);               
                mean_dist += Static.relativeDistance(monte_carlo_medians.ToArray(), ddr_medians.ToArray());
                mean_CVM += Static.CVM(monte_carlo_list, ddr_list);
                //foreach (double s in ddr_medians)
