                //Console.WriteLine();

                //foreach (double s in monte_carlo_medians)
                //{
                //    Console.Write("{0:0.00} ", s);
                //}
                //Console.WriteLine("\n");
            }
            mean_dist /= NTests;
            mean_CVM /= NTests;
            Console.WriteLine("Accuracy metric mean median tree {0:0.0000}", mean_dist);
            Console.WriteLine("Accuracy metric Cramer von Mises order one {0:0.0000}", mean_CVM);
        }
